def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length
    groups = {}
    for word in words:
        length = len(word)
        if length not in groups:
            groups[length] = []
        groups[length].append(word)

    sorted_words = []
    # Sort each group by reverse-alphabetical order and then by increasing length
    for length, group in sorted(groups.items()):
        sorted_words.extend(sorted(group, reverse=True))

    if k > len(sorted_words):
        return None

    return sorted_words[k-1]
